165→    synchronized void put(final Bytes key, final LRUCacheEntry value) {
166→        if (!value.isDirty() && dirtyKeys.contains(key)) {
167→            throw new IllegalStateException(
168→                String.format(
169→                    "Attempting to put a clean entry for key [%s] into NamedCache [%s] when it already contains a dirty entry for the same key",
170→                    key, name
171→                )
172→            );
173→        }
174→        LRUNode node = cache.get(key);
175→        if (node != null) {
176→            numOverwrites++;
177→
178→            currentSizeBytes -= node.size();
179→            node.update(value);
180→            updateLRU(node);
181→        } else {
182→            node = new LRUNode(key, value);
183→            // put element
184→            putHead(node);
185→            cache.put(key, node);
186→        }
187→        if (value.isDirty()) {
188→            // first remove and then add so we can maintain ordering as the arrival order of the records.
189→            dirtyKeys.remove(key);
190→            dirtyKeys.add(key);
191→        }
192→        currentSizeBytes += node.size();
193→        totalCacheSizeSensor.record(currentSizeBytes);
194→    }
