219→    private void remove(final LRUNode node) {
220→        if (node.previous != null) {
221→            node.previous.next = node.next;
222→        } else {
223→            head = node.next;
224→        }
225→        if (node.next != null) {
226→            node.next.previous = node.previous;
227→        } else {
228→            tail = node.previous;
229→        }
230→    }
