import org.apache.kafka.streams.query.QueryResult;
import org.apache.kafka.streams.state.KeyValueStore;
import org.apache.kafka.streams.query.KeyQuery;

/**
 * Fray test that exercises the concurrent put/query paths on InMemoryKeyValueStore
 * to detect the ABBA deadlock between the store's intrinsic lock and its position lock.
 */
public class InMemoryKeyValueStoreDeadlockTest {

    public static void main(String[] args) throws Exception {
        final InMemoryKeyValueStore store = new InMemoryKeyValueStore("test-store");
        // Initialize store without a full StateStoreContext — position is already usable
        // We don't call init() since we don't need the full processor context for this test.
        // The position field is final and initialized at construction.

        final Bytes key = Bytes.wrap("key".getBytes());
        final byte[] value = "value".getBytes();

        // Pre-populate so get() returns data
        store.put(key, value);

        // Thread 1: put path — acquires `this` then `position`
        final Thread writer = new Thread(() -> {
            store.put(key, value);
        }, "writer-thread");

        // Thread 2: query path (simulates IQv2) — acquires `position` then `this`
        // We directly call handleBasicQueries to reproduce the exact lock ordering
        final Thread reader = new Thread(() -> {
            final Position position = store.getPosition();
            final KeyQuery<Bytes, byte[]> query = KeyQuery.withKey(key);
            StoreQueryUtils.handleBasicQueries(
                query,
                PositionBound.unbounded(),
                new QueryConfig(false),
                store,
                position,
                null
            );
        }, "reader-thread");

        writer.start();
        reader.start();
        writer.join();
        reader.join();
    }
}

